            ParserConfigurationException pce = new ParserConfigurationException("Failed to configure secure DocumentBuilder: " + e.getMessage());
            pce.initCause(e);
            throw pce;
        }

        try {
            // Create SAX parser
            javax.xml.parsers.SAXParser saxParser = saxFactory.newSAXParser();

            // Create DocumentBuilder
            DocumentBuilder docBuilder = docFactory.newDocumentBuilder();

            // Create empty Document as target
            Document document = docBuilder.newDocument();

            // Create Transformer for SAX to DOM conversion
            TransformerFactory transformerFactory = TransformerFactory.newInstance();

            // Secure TransformerFactory configuration
            try {
                transformerFactory.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
                transformerFactory.setAttribute(XMLConstants.ACCESS_EXTERNAL_DTD, "");
                transformerFactory.setAttribute(XMLConstants.ACCESS_EXTERNAL_STYLESHEET, "");
            } catch (Exception e) {
                // Log warning but continue - some implementations may not support these features
                System.err.println("Warning: Could not configure all Transformer security features: " + e.getMessage());
            }

            Transformer transformer = transformerFactory.newTransformer();

            // Parse XML using SAX parser and convert to DOM Document
            SAXSource saxSource = new SAXSource(saxParser.getXMLReader(), 
                    new org.xml.sax.InputSource(xmlFile.getAbsolutePath()));
            DOMResult domResult = new DOMResult(document);
            transformer.transform(saxSource, domResult);

            return document;

        } catch (javax.xml.transform.TransformerException e) {
            throw new SAXException("Failed to transform XML to Document: " + e.getMessage(), e);
        } catch (SAXException e) {
            throw new SAXException("Invalid XML format in file: " + configPath + " - " + e.getMessage(), e);
        } catch (ParserConfigurationException e) {
            ParserConfigurationException pce = new ParserConfigurationException("Parser configuration error: " + e.getMessage());
            pce.initCause(e);
            throw pce;
        }
    }

    /**
     * Utility method to validate XML file before parsing
     *
     * @param configPath Path to the XML file
     * @return true if file appears to be valid XML, false otherwise
     */
    public boolean validateXmlFile(String configPath) {
        if (configPath == null || configPath.trim().isEmpty()) {
            return false;
        }

        File file = new File(configPath);
        if (!file.exists() || !file.canRead() || file.length() == 0) {
            return false;
        }

        // Check if file has XML-like extension (optional)
        String fileName = file.getName().toLowerCase();
        return fileName.endsWith(".xml");
    }
